const PEMKOT_LOGO_BASE64 = "data:image/png;base64,";
/**
 * E-Presensi Standalone JS Asset
 * Universal Password Toggle & Dynamic Event Modals Handler
 */

document.addEventListener('DOMContentLoaded', function () {
  // 1. Password Toggle Handlers
  initPasswordToggle('toggle-password', 'password');
  initPasswordToggle('toggle-password-confirm', 'password_confirmation');
  initPasswordToggle('toggle-register-password', 'password');
  initPasswordToggle('toggle-register-confirm', 'password_confirmation');
  initPasswordToggle('toggle-admin-event-password', 'admin-event-password');
  initPasswordToggle('toggle-user-event-password', 'user-event-password');
  initPasswordToggle('toggle-edit-event-password', 'edit-event-password');

  // 2. Dynamic Event Modals
  initEditEventModal();
  initQrModal();
});

function initPasswordToggle(toggleBtnId, passwordInputId) {
  const toggleBtn = document.getElementById(toggleBtnId);
  const passwordInput = document.getElementById(passwordInputId);

  if (!toggleBtn || !passwordInput) return;

  const eyeSvg = `<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" class="bi bi-eye" viewBox="0 0 16 16" style="width: 16px; height: 16px;"><path d="M16 8s-3-5.5-8-5.5S0 8 0 8s3 5.5 8 5.5S16 8 16 8zM1.173 8a13.133 13.133 0 0 1 1.66-2.043C4.12 4.668 5.88 4 8 4c2.12 0 3.879.668 5.168 1.957A13.133 13.133 0 0 1 14.828 8c-.058.087-.122.183-.195.288-.335.48-.83 1.12-1.465 1.755C11.879 11.332 10.119 12 8 12c-2.12 0-3.879-.668-5.168-1.957A13.133 13.133 0 0 1 1.172 8z"/><path d="M8 5.5a2.5 2.5 0 1 0 0 5 2.5 2.5 0 0 0 0-5zM4.5 8a3.5 3.5 0 1 1 7 0 3.5 3.5 0 0 1-7 0z"/></svg>`;
  const eyeSlashSvg = `<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" class="bi bi-eye-slash" viewBox="0 0 16 16" style="width: 16px; height: 16px;"><path d="M13.359 11.238C15.06 9.72 16 8 16 8s-3-5.5-8-5.5a8.09 8.09 0 0 0-2.312.333L9.73 6.868c.403-.345.925-.535 1.47-.535 1.38 0 2.5 1.12 2.5 2.5 0 .545-.19 1.067-.535 1.47l2.194 2.193zm-5.09-5.09L10 8.357A2.49 2.49 0 0 0 8.005 6.5a2.49 2.49 0 0 0-2.464 1.857l-1.815-1.815C4.857 6.136 6.326 5.5 8 5.5z"/><path d="M8 12c-2.12 0-3.879-.668-5.168-1.957a13.133 13.133 0 0 1-1.66-2.043C1.22 7.712 1.9 6.837 2.73 6.012L1.082 4.364A8.907 8.907 0 0 0 0 8s3 5.5 8 5.5a8.09 8.09 0 0 0 2.312-.333L8.641 11.51c-.403.345-.925.535-1.47.535z"/><path d="M12.42 13.482a8.238 8.238 0 0 1-2.585.836l1.246 1.246a.5.5 0 0 0 .707-.707l-1.368-1.375z"/><path d="M5.433 11.104A3.5 3.5 0 0 1 4.5 8a3.5 3.5 0 0 1 1.037-2.433l-1.037-1.037a5 5 0 0 0-.25 5.576l1.183 1.183-.003-.186zm6.825 2.193a5 5 0 0 0 .25-5.576l-1.183-1.183.003.186a3.5 3.5 0 0 1 1.037 3.03l1.183 1.183-.29-.64z"/></svg>`;

  toggleBtn.addEventListener('click', function() {
    if (passwordInput.type === 'password') {
      passwordInput.type = 'text';
      toggleBtn.innerHTML = eyeSlashSvg;
    } else {
      passwordInput.type = 'password';
      toggleBtn.innerHTML = eyeSvg;
    }
  });
}

function initEditEventModal() {
  const editModalEl = document.getElementById('editEventModal');
  if (!editModalEl) return;

  const form = document.getElementById('edit-event-form');
  const nameInput = document.getElementById('edit-event-name');
  const dateInput = document.getElementById('edit-event-date');
  const dateEndInput = document.getElementById('edit-event-date-end');
  const timeStartInput = document.getElementById('edit-event-time-start');
  const timeEndInput = document.getElementById('edit-event-time-end');
  const audienceSelect = document.getElementById('edit-event-audience-type');
  const accessSelect = document.getElementById('edit-event-access-type');
  const passwordWrapper = document.getElementById('edit-event-password-wrapper');
  const passwordInput = document.getElementById('edit-event-password');
  const customFieldsContainer = document.getElementById('edit-custom-fields');
  const addCustomFieldBtn = document.getElementById('edit-add-custom-field');

  if (accessSelect && passwordWrapper) {
    accessSelect.addEventListener('change', function () {
      passwordWrapper.style.display = this.value === 'privat' ? 'block' : 'none';
    });
  }

  const btnGenerateEditPassword = document.getElementById('btn-generate-edit-password');
  if (btnGenerateEditPassword && passwordInput) {
    btnGenerateEditPassword.addEventListener('click', function () {
      const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
      let randomPass = '';
      for (let i = 0; i < 6; i++) {
        randomPass += chars.charAt(Math.floor(Math.random() * chars.length));
      }
      passwordInput.value = randomPass;
    });
  }

  editModalEl.addEventListener('show.bs.modal', function (e) {
    const btn = e.relatedTarget;
    if (!btn) return;

    const action = btn.getAttribute('data-action');
    const name = btn.getAttribute('data-name');
    const date = btn.getAttribute('data-date');
    const dateEnd = btn.getAttribute('data-date-end') || date;
    const timeStart = btn.getAttribute('data-time-start');
    const timeEnd = btn.getAttribute('data-time-end');
    const audienceType = btn.getAttribute('data-audience-type');
    const accessType = btn.getAttribute('data-access-type');
    const password = btn.getAttribute('data-password') || '';
    
    let fields = [];
    try {
      fields = JSON.parse(btn.getAttribute('data-fields') || '[]');
    } catch (err) {
      fields = [];
    }

    let customFields = [];
    try {
      customFields = JSON.parse(btn.getAttribute('data-custom-fields') || '[]');
    } catch (err) {
      customFields = [];
    }

    if (form && action) form.action = action;
    if (nameInput) nameInput.value = name || '';
    if (dateInput) dateInput.value = date || '';
    if (dateEndInput) dateEndInput.value = dateEnd || '';
    if (timeStartInput) timeStartInput.value = timeStart || '';
    if (timeEndInput) timeEndInput.value = timeEnd || '';
    if (audienceSelect) audienceSelect.value = audienceType || 'semua';
    if (accessSelect) {
      accessSelect.value = accessType || 'publik';
      passwordWrapper.style.display = accessType === 'privat' ? 'block' : 'none';
    }
    if (passwordInput) passwordInput.value = password;

    document.querySelectorAll('.edit-field-checkbox').forEach(cb => {
      cb.checked = fields.includes(cb.name);
    });

    if (customFieldsContainer) {
      customFieldsContainer.innerHTML = '';
      customFields.forEach(cf => {
        appendCustomFieldRow(customFieldsContainer, cf.label, cf.type);
      });
    }
  });

  if (addCustomFieldBtn && customFieldsContainer) {
    addCustomFieldBtn.addEventListener('click', () => {
      appendCustomFieldRow(customFieldsContainer, '', 'text');
    });
  }
}

function appendCustomFieldRow(container, label = '', type = 'text') {
  const row = document.createElement('div');
  row.className = 'row mb-2 align-items-center';
  row.innerHTML = `
    <div class="col-6">
      <input type="text" name="custom_labels[]" value="${escapeHtml(label)}" class="form-control" placeholder="Nama field" required>
    </div>
    <div class="col-3">
      <select name="custom_types[]" class="form-control">
        <option value="text" ${type === 'text' ? 'selected' : ''}>Text</option>
        <option value="number" ${type === 'number' ? 'selected' : ''}>Number</option>
        <option value="date" ${type === 'date' ? 'selected' : ''}>Date</option>
        <option value="email" ${type === 'email' ? 'selected' : ''}>Email</option>
      </select>
    </div>
    <div class="col-3 text-end">
      <button type="button" class="btn btn-outline-danger btn-xs mb-0 remove-custom-field d-flex align-items-center justify-content-center gap-1 w-100">
        <i class="ni ni-fat-remove me-1"></i>
        <span class="d-none d-sm-inline">Hapus</span>
      </button>
    </div>`;

  row.querySelector('.remove-custom-field').addEventListener('click', () => {
    row.remove();
  });

  container.appendChild(row);
}

function initQrModal() {
  const qrModalEl = document.getElementById('qrModal');
  if (!qrModalEl) return;

  qrModalEl.addEventListener('show.bs.modal', function (e) {
    const btn = e.relatedTarget;
    if (!btn) return;

    const url = btn.getAttribute('data-url');
    const name = btn.getAttribute('data-name');
    const schedule = btn.getAttribute('data-schedule');
    const eventId = btn.getAttribute('data-event-id');

    const titleEl = document.getElementById('qrModalEventTitle');
    const scheduleEl = document.querySelector('#qrModalEventSchedule span');
    const urlEl = document.getElementById('qrModalEventUrl');
    const qrBox = document.getElementById('qrcode-box');
    const downloadBtn = document.getElementById('qrModalDownloadBtn');

    if (titleEl) titleEl.textContent = name;
    if (scheduleEl) scheduleEl.textContent = schedule;
    if (urlEl) urlEl.textContent = url;

    if (downloadBtn) {
      downloadBtn.setAttribute('data-url', url);
      downloadBtn.setAttribute('data-name', name);
      downloadBtn.setAttribute('data-event-id', eventId);
    }

    if (qrBox) {
      qrBox.innerHTML = '';
      if (typeof QRCode !== 'undefined') {
        try {
          new QRCode(qrBox, {
            text: url,
            width: 180,
            height: 180,
            colorDark: "#0f172a",
            colorLight: "#ffffff",
            correctLevel: QRCode.CorrectLevel.H
          });
        } catch (err) {
          qrBox.innerHTML = `<img src="https://api.qrserver.com/v1/create-qr-code/?size=180x180&data=${encodeURIComponent(url)}" alt="QR Code" class="img-fluid rounded" crossorigin="anonymous" />`;
        }
      } else {
        qrBox.innerHTML = `<img src="https://api.qrserver.com/v1/create-qr-code/?size=180x180&data=${encodeURIComponent(url)}" alt="QR Code" class="img-fluid rounded" crossorigin="anonymous" />`;
      }
    }
  });

  const downloadBtn = document.getElementById('qrModalDownloadBtn');
  if (downloadBtn) {
    downloadBtn.addEventListener('click', function (e) {
      e.preventDefault();
      downloadQrCodeDirect(this);
    });
  }
}

function downloadQrCodeDirect(btn) {
  try {
    const url = (btn && btn.getAttribute('data-url')) || (document.getElementById('qrModalEventUrl') ? document.getElementById('qrModalEventUrl').textContent : '');
    const name = (btn && btn.getAttribute('data-name')) || (document.getElementById('qrModalEventTitle') ? document.getElementById('qrModalEventTitle').textContent : 'event');
    const eventName = slugify(name || 'event');

    if (!url) {
      alert('URL Event tidak ditemukan!');
      return;
    }

    const qrCanvas = document.querySelector('#qrcode-box canvas');
    const qrImg = document.querySelector('#qrcode-box img');
    const sourceEl = qrCanvas || qrImg;

    const canvas = document.createElement('canvas');
    canvas.width = 600;
    canvas.height = 600;
    const ctx = canvas.getContext('2d');

    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, 600, 600);

    if (sourceEl) {
      ctx.imageSmoothingEnabled = false;
      ctx.drawImage(sourceEl, 0, 0, 600, 600);

      const logoOverlayImg = document.querySelector('#qrCardArea img[alt="Logo Pemkot"]');
      const logoSrc = (logoOverlayImg && logoOverlayImg.src) || window.pemkotLogoPath || '/assets/argon-dashboard-pro-html-v2.0.5/assets/img/logos/GKV307_Kota Malang-logobase.net.png';

      const logo = new Image();
      logo.crossOrigin = "anonymous";
      logo.onload = function () {
        try {
          const logoSize = 120;
          const center = 300;

          ctx.fillStyle = '#ffffff';
          ctx.beginPath();
          ctx.arc(center, center, (logoSize + 16) / 2, 0, 2 * Math.PI);
          ctx.fill();
          ctx.lineWidth = 3;
          ctx.strokeStyle = '#cbd5e1';
          ctx.stroke();

          ctx.drawImage(logo, center - logoSize / 2, center - logoSize / 2, logoSize, logoSize);

          const dataUrl = canvas.toDataURL('image/png');
          const a = document.createElement('a');
          a.href = dataUrl;
          a.download = 'QR_Code_' + eventName + '.png';
          document.body.appendChild(a);
          a.click();
          setTimeout(() => {
            if (document.body.contains(a)) document.body.removeChild(a);
          }, 200);
        } catch (e) {
          console.error('Error in logo.onload:', e);
          window.open(`https://api.qrserver.com/v1/create-qr-code/?size=600x600&data=${encodeURIComponent(url)}`, '_blank');
        }
      };
      logo.onerror = function () {
        try {
          const dataUrl = canvas.toDataURL('image/png');
          const a = document.createElement('a');
          a.href = dataUrl;
          a.download = 'QR_Code_' + eventName + '.png';
          document.body.appendChild(a);
          a.click();
          setTimeout(() => {
            if (document.body.contains(a)) document.body.removeChild(a);
          }, 200);
        } catch (e) {
          console.error('Error in logo.onerror:', e);
          window.open(`https://api.qrserver.com/v1/create-qr-code/?size=600x600&data=${encodeURIComponent(url)}`, '_blank');
        }
      };
      logo.src = typeof PEMKOT_LOGO_BASE64 !== 'undefined' ? PEMKOT_LOGO_BASE64 : logoSrc;
    } else {
      window.open(`https://api.qrserver.com/v1/create-qr-code/?size=600x600&data=${encodeURIComponent(url)}`, '_blank');
    }
  } catch (e) {
    console.error('Error in downloadQrCodeDirect:', e);
    alert('Terjadi kesalahan saat mengunduh QR Code: ' + e.message);
  }
}

window.downloadQrCodeDirect = downloadQrCodeDirect;

function triggerDownload(href, filename) {
  const a = document.createElement('a');
  a.href = href;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
}

function escapeHtml(str) {
  return (str || '').replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;");
}

function slugify(text) {
  return text.toString().toLowerCase()
    .replace(/\s+/g, '-')
    .replace(/[^\w\-]+/g, '')
    .replace(/\-\-+/g, '-')
    .replace(/^-+/, '')
    .replace(/-+$/, '');
}
